function evalRPN(tokens: string[]): number {
  const st: number[] = [];
  for (const tok of tokens) {
    if (tok === "+" || tok === "-" || tok === "*" || tok === "/") {
      const b = st.pop()!, a = st.pop()!;
      let v = 0;
      if (tok === "+") v = a + b;
      else if (tok === "-") v = a - b;
      else if (tok === "*") v = a * b;
      else v = Math.trunc(a / b);
      st.push(v);
    } else {
      st.push(parseInt(tok, 10));
    }
  }
  return st[0];
}
